+lanelet::ConstLanelets query::laneletLayer(const lanelet::LaneletMapConstPtr & ll_map)
+{
+  lanelet::ConstLanelets lanelets;
+  if (!ll_map) {
+    std::cerr << "No map received!";
+    return lanelets;
