+  visualization::initLineStringMarker(&line_marker, "map", "no_stopping_area_stopline", line_c);
+
+  for (const auto & no_reg_elem : no_reg_elems) {
+    marker.points.clear();
+    marker.colors.clear();
+    marker.id = static_cast<int32_t>(no_reg_elem->id());
